using System;
using System.IO;
using Aspose.BarCode;
using Aspose.BarCode.Generation;

/// <summary>
/// Demonstrates generating a Royal Mail 4-state Customer Code (RM4SCC) barcode
/// and outputting the size of the resulting PNG byte array.
/// </summary>
class Program
{
    /// <summary>
    /// Entry point of the application.
    /// Generates an RM4SCC barcode, saves it to a memory stream as PNG,
    /// and writes the length of the generated byte array to the console.
    /// </summary>
    static void Main()
    {
        // Sample codetext for RM4SCC (Royal Mail 4-state Customer Code)
        string codeText = "AB1234567";

        // Create the barcode generator for RM4SCC using the specified codetext
        using (var generator = new BarcodeGenerator(EncodeTypes.RM4SCC, codeText))
        {
            // Set a custom XDimension (module width) in points (2.5 points)
            generator.Parameters.Barcode.XDimension.Point = 2.5f;

            // Export the barcode image to a memory stream in PNG format
            using (var ms = new MemoryStream())
            {
                generator.Save(ms, BarCodeImageFormat.Png);
                byte[] barcodeBytes = ms.ToArray();

                // Output the size of the generated byte array
                Console.WriteLine($"Generated RM4SCC barcode byte array length: {barcodeBytes.Length}");
            }
        }
    }
}